trigger.body:
	vCheck NUMBER;
BEGIN

    IF AD_isTriggerEnabled()='N' THEN RETURN;
    END IF;

	IF TG_OP IN ('INSERT','UPDATE') THEN
		SELECT COUNT(*) INTO vCheck FROM scrvro_route_period WHERE isactive='Y'
			AND scrvro_route_period_id!=:NEW.scrvro_route_period_id AND c_period_id=:NEW.c_period_id;
		IF vCheck > 0 AND :NEW.isactive='Y' THEN
			RAISE_APPLICATION_ERROR(-20000, '@Scrvro_VendorRoutePeriodActive@') ;
		END IF;
	END IF;

	END SCRVRO_ROUTE_PERIOD_1_TRG
